import { Component } from '@angular/core';

@Component({
    selector: 'app-links',
    templateUrl: './links.component.html',
    styleUrls: ['./links.component.scss']
})
export default class LinksComponent {
    openURL( url: string ): void {
    window.open(url, '_blank');
    }
}



